import { Button, Card, CardContent, CardHeader, Dialog, DialogContent, DialogTitle, Paper, Typography } from '@material-ui/core'
import React from 'react'
import { useState } from 'react'




export default function Quiz() {
    const [quiz, setQuiz] = useState(false);

    const openQuiz = () => {
        setQuiz(true)
    };
    const closeQuiz = () => {
        setQuiz(false)
    };

  return (
    <>
    <Button variant='contained' color='secondary' onClick={openQuiz}>
        Open Dialog
    </Button>
        <Dialog open={quiz} onClose={closeQuiz} fullScreen>
            <DialogTitle>Web Application Development</DialogTitle>
            <DialogContent>
                <Card>
                    <CardHeader title='Quiz 1' subheader='part 1' />
                    <CardContent>
                        <Typography>

                        </Typography>
                    </CardContent>
                </Card>
            </DialogContent>
        </Dialog>
    </>
  )
}
